def find_duplicates(items):
    seen = set()
    duplicates = []
    duplicate_set = set()

    for item in items:
        if item in seen and item not in duplicate_set:
            duplicates.append(item)
            duplicate_set.add(item)
        seen.add(item)

    return duplicates

import json

def validate_json(json_string, required_keys):
    try:
        data = json.loads(json_string)
    except (json.JSONDecodeError, TypeError):
        return (None, ['INVALID_JSON'])

    missing = [key for key in required_keys if key not in data]
    return (data, missing)

def diff_dicts(expected, actual, path=''):
    differences = []

    all_keys = set(expected.keys()) | set(actual.keys())

    for key in sorted(all_keys):
        full_path = f'{path}.{key}' if path else key

        if key not in expected:
            differences.append(f'{full_path}: key missing in expected')
        elif key not in actual:
            differences.append(f'{full_path}: key missing in actual')
        elif isinstance(expected[key], dict) and isinstance(actual[key], dict):
            differences.extend(diff_dicts(expected[key], actual[key], full_path))
        elif expected[key] != actual[key]:
            differences.append(f'{full_path}: expected {expected[key]!r}, got {actual[key]!r}')

    return differences

from collections import defaultdict

def group_by(items, key):
    groups = defaultdict(list)
    for item in items:
        groups[item[key]].append(item)
    return dict(groups)

def flatten(nested):
    result = []
    for item in nested:
        if isinstance(item, list):
            result.extend(item)
        else:
            result.append(item)
    return result

