def assert_subset(subset, full):
    mismatches = []
    for key, expected_value in subset.items():
        if key not in full:
            mismatches.append(f"Key {key!r}: missing from actual response")
        elif full[key] != expected_value:
            mismatches.append(f"Key {key!r}: expected {expected_value!r}, got {full[key]!r}")
    if mismatches:
        raise AssertionError('\n'.join(mismatches))

import string

def word_frequency(text):
    counts = {}
    for word in text.split():
        cleaned = word.strip(string.punctuation).lower()
        if cleaned:
            counts[cleaned] = counts.get(cleaned, 0) + 1
    return counts

