def validate_response_list(items, schema):
    errors = []
    for idx, item in enumerate(items):
        for field, expected_type in schema.items():
            if field not in item:
                errors.append(f"Item {idx}: field {field!r} is missing")
            elif not isinstance(item[field], expected_type):
                actual_type = type(item[field]).__name__
                errors.append(
                    f"Item {idx}: field {field!r} expected {expected_type.__name__}, got {actual_type}"
                )
    return errors
